  // --- Loading overlay ---
  var mapEl = document.getElementById(MAP_ID);
  var overlay = document.createElement('div');
  overlay.className = 'udc-loading-overlay';
  overlay.innerHTML = '<div class="udc-spinner"></div><p>Loading data centers&hellip;</p>';
  mapEl.appendChild(overlay);

  function removeOverlay() {
    if (overlay && overlay.parentNode) overlay.parentNode.removeChild(overlay);
  }

  function showError(msg) {
    removeOverlay();
    var err = document.createElement('div');
    err.className = 'udc-error-overlay';
    err.innerHTML = '<p>' + msg + '</p><button class="udc-retry-btn" id="' + SLUG + '-retry">Retry</button>';
    mapEl.appendChild(err);
    var btn = document.getElementById(SLUG + '-retry');
    if (btn) btn.addEventListener('click', function () {
      if (err.parentNode) err.parentNode.removeChild(err);
      sessionStorage.removeItem(CACHE_KEY);
      mapEl.appendChild(overlay);
      loadData();
    });
  }

  // --- Helpers ---
  function escHtml(s) {
    return String(s)
      .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  // --- Buffer ---
  var bufferLayer = null;

  function drawBuffer(latlng, miles) {
    if (bufferLayer) { map.removeLayer(bufferLayer); bufferLayer = null; }
    var radius = miles * 1609.344;
    bufferLayer = L.circle(latlng, {
      radius: radius, color:'#2563EB', weight:2, fillColor:'#2563EB',
      fillOpacity:0.07, dashArray:'7 5', interactive:false
    }).addTo(map);
    map.fitBounds(bufferLayer.getBounds(), { padding:[40,40] });
    var btn = document.getElementById(SLUG + '-clear-buffer');
    if (btn) btn.style.display = '';
  }

  function clearBuffer() {
    if (bufferLayer) { map.removeLayer(bufferLayer); bufferLayer = null; }
    var btn = document.getElementById(SLUG + '-clear-buffer');
    if (btn) btn.style.display = 'none';
  }

  var clearBufBtn = document.getElementById(SLUG + '-clear-buffer');
  if (clearBufBtn) {
    clearBufBtn.style.display = 'none';
    clearBufBtn.addEventListener('click', clearBuffer);
  }

  map.on('popupopen', function (e) {
    var el = e.popup.getElement();
    if (!el) return;
    var btn = el.querySelector('.udc-buffer-btn');
    if (!btn) return;
    btn.addEventListener('click', function () {
      var input = el.querySelector('.udc-buffer-input');
      var miles = Math.max(1, parseFloat(input ? input.value : 25) || 25);
      var ll = e.popup.getLatLng();
      map.closePopup();
      drawBuffer(ll, miles);
    });
  });

  // --- Popup ---
  function makePopup(d) {
    var name = d.name || 'Data Center';
    var rows = '';
    if (d.operator) rows += '<tr><th>Operator</th><td>' + escHtml(d.operator) + '</td></tr>';
    var locParts = [d.city];
    if (d.county) locParts.push(d.county + ' County');
    if (d.state) locParts.push(STATE_NAMES[d.state] || d.state);
    var loc = locParts.filter(Boolean).join(', ');
    if (loc) rows += '<tr><th>Location</th><td>' + escHtml(loc) + '</td></tr>';
    if (d.website) {
      var url = d.website.match(/^https?:\/\//) ? d.website : 'https://' + d.website;
      rows += '<tr><th>Website</th><td><a href="' + escHtml(url) + '" target="_blank" rel="noopener">' + escHtml(d.website.replace(/^https?:\/\//,'')) + '</a></td></tr>';
    }
    var osmType = d.osmType === 'node' ? 'node' : 'way';
    var osmUrl = 'https://www.openstreetmap.org/' + osmType + '/' + d.osmId;
    return (
      '<div class="udc-popup">' +
        '<h3>' + escHtml(name) + '</h3>' +
        (rows ? '<table>' + rows + '</table>' : '') +
        '<div class="udc-buffer-control">' +
          '<span class="udc-buffer-label">Draw buffer:</span>' +
          '<input type="number" class="udc-buffer-input" value="25" min="1" max="500" />' +
          '<span class="udc-buffer-unit">miles</span>' +
          '<button class="udc-buffer-btn">Draw</button>' +
        '</div>' +
        '<a href="' + osmUrl + '" target="_blank" rel="noopener" class="udc-osm-link">View on OpenStreetMap</a>' +
      '</div>'
    );
  }

  // --- Render ---
  var allData = [];

  function updateCount(shown, total, st) {
    var el = document.getElementById(SLUG + '-count');
    if (!el) return;
    if (st) {
      el.textContent = shown.toLocaleString() + ' data centers in ' + (STATE_NAMES[st] || st);
    } else {
      el.textContent = shown.toLocaleString() + ' data centers across the United States';
    }
  }

  function renderMarkers(st) {
    clusterGroup.clearLayers();
    var filtered = st
      ? allData.filter(function (d) { return d.state === st; })
      : allData;

    var layers = filtered.map(function (d) {
      var m = L.circleMarker([d.lat, d.lon], MARKER_STYLE);
      m.bindPopup(makePopup(d), { maxWidth: 290 });
      m._udc = d;
      return m;
    });
    clusterGroup.addLayers(layers);
    updateCount(filtered.length, allData.length, st);

    if (st && clusterGroup.getBounds().isValid()) {
      map.fitBounds(clusterGroup.getBounds(), { padding:[40,40], maxZoom: 9 });
    }
  }

  function buildStateDropdown() {
    var sel = document.getElementById(SLUG + '-state-select');
    if (!sel) return;
    var seen = {};
    allData.forEach(function (d) { if (d.state) seen[d.state] = true; });
    var states = Object.keys(seen).sort(function (a,b) {
      return (STATE_NAMES[a] || a).localeCompare(STATE_NAMES[b] || b);
    });
    states.forEach(function (a) {
      var opt = document.createElement('option');
      opt.value = a;
      opt.textContent = STATE_NAMES[a] || a;
      if (a === currentState) opt.selected = true;
      sel.appendChild(opt);
    });
  }

